import{_ as t,c as s,o as i,ae as e}from"./chunks/framework.BQlYxExx.js";const c=JSON.parse('{"title":"🎯 Java订单超时取消与支付回调并发 - 2026面试场景题","description":"Java面试高频场景题：订单30分钟未支付自动取消与支付回调并发冲突，幽灵订单问题解决方案，数据库乐观锁解决并发覆盖，二次查库保证幂等性，MQ异步退款，分布式防抖，Redis分布式锁，大厂Java后端面试必考并发场景设计题，订单系统并发安全，支付回调幂等处理，超时订单取消机制","frontmatter":{"title":"🎯 Java订单超时取消与支付回调并发 - 2026面试场景题","description":"Java面试高频场景题：订单30分钟未支付自动取消与支付回调并发冲突，幽灵订单问题解决方案，数据库乐观锁解决并发覆盖，二次查库保证幂等性，MQ异步退款，分布式防抖，Redis分布式锁，大厂Java后端面试必考并发场景设计题，订单系统并发安全，支付回调幂等处理，超时订单取消机制","keywords":["Java面试题","订单超时取消","支付回调并发","幽灵订单","乐观锁","幂等性","分布式锁","Redis防抖","MQ异步退款","并发场景题","Java后端","八股文","系统设计面试"]},"headers":[],"relativePath":"JAVA.md","filePath":"JAVA.md"}'),l={name:"JAVA.md"};function n(h,a,r,o,d,p){return i(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="java" tabindex="-1">JAVA <a class="header-anchor" href="#java" aria-label="Permalink to &quot;JAVA&quot;">​</a></h1><h2 id="面试官-订单30分钟未支付自动取消-用户在第29分59秒付了钱-取消和支付回调同时到达-怎么处理" tabindex="-1">面试官：订单30分钟未支付自动取消，用户在第29分59秒付了钱，取消和支付回调同时到达，怎么处理？ <a class="header-anchor" href="#面试官-订单30分钟未支付自动取消-用户在第29分59秒付了钱-取消和支付回调同时到达-怎么处理" aria-label="Permalink to &quot;面试官：订单30分钟未支付自动取消，用户在第29分59秒付了钱，取消和支付回调同时到达，怎么处理？&quot;">​</a></h2><blockquote><p><strong>核心问题</strong>：订单超时取消任务和支付回调并发执行，产生「幽灵订单」——数据库显示已支付但业务已取消，库存已释放。</p></blockquote><h3 id="❌-错误答法" tabindex="-1">❌ 错误答法 <a class="header-anchor" href="#❌-错误答法" aria-label="Permalink to &quot;❌ 错误答法&quot;">​</a></h3><p>先查订单状态，如果是未支付就改成已取消/已支付，谁先到谁执行。</p><p><strong>为什么错</strong>：这是典型的**检查后执行（TOCTOU）**竞态问题。取消任务查到「未支付」，支付回调查到也是「未支付」，取消任务先 update 成「已取消」，支付回调紧接着 update 覆盖成「已支付」，数据库状态和业务状态不一致。</p><h3 id="✅-正确方案-并发三道防线" tabindex="-1">✅ 正确方案：并发三道防线 <a class="header-anchor" href="#✅-正确方案-并发三道防线" aria-label="Permalink to &quot;✅ 正确方案：并发三道防线&quot;">​</a></h3><h4 id="第一道防线-—-数据库乐观锁-解决并发覆盖" tabindex="-1">第一道防线 — 数据库乐观锁（解决并发覆盖） <a class="header-anchor" href="#第一道防线-—-数据库乐观锁-解决并发覆盖" aria-label="Permalink to &quot;第一道防线 — 数据库乐观锁（解决并发覆盖）&quot;">​</a></h4><p>核心原则：<strong>永远不要相信在内存里查到的状态</strong>。</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;PAID&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, pay_time </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> NOW</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> order_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ? </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;UNPAID&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>将前置条件 <code>status = &#39;UNPAID&#39;</code> 带进 WHERE 子句，数据库行锁会排队执行：</p><ul><li>先抢到锁的更新成功，影响行数 = 1</li><li>后到的因为条件不满足，影响行数 = 0，直接返回</li></ul><p>从根源杜绝覆盖写。</p><h4 id="第二道防线-—-二次查库-解决幂等" tabindex="-1">第二道防线 — 二次查库（解决幂等） <a class="header-anchor" href="#第二道防线-—-二次查库-解决幂等" aria-label="Permalink to &quot;第二道防线 — 二次查库（解决幂等）&quot;">​</a></h4><p>UPDATE 返回 0 时，<strong>不能</strong>直接发起退款（考虑支付宝回调重试机制，可能第二次回调时状态已是已支付）。</p><blockquote><p>UPDATE 返回 0 → 二次查库：</p><ul><li>状态已支付 → 直接返回成功（幂等处理）</li><li>状态已取消 → 走异常处理</li></ul></blockquote><h4 id="第三道防线-—-异步退款-订单捞回-保障体验" tabindex="-1">第三道防线 — 异步退款 + 订单捞回（保障体验） <a class="header-anchor" href="#第三道防线-—-异步退款-订单捞回-保障体验" aria-label="Permalink to &quot;第三道防线 — 异步退款 + 订单捞回（保障体验）&quot;">​</a></h4><blockquote><ol><li><strong>拒绝同步退款</strong>：回调接口里不直接调退款 API，用 MQ 异步处理，避免接口超时拖垮服务</li><li><strong>业务容错思维</strong>：用户晚了几秒支付，优先捞回订单成交，而不是冷冰冰退款——<strong>把钱收进来永远比推出去更重要</strong></li><li><strong>分布式防抖</strong>：多节点部署时，超时任务可能同时唤醒多台机器，应用层加 Redis 分布式锁，只让一个节点执行取消，其余直接防抖</li></ol></blockquote><h3 id="防线总结" tabindex="-1">防线总结 <a class="header-anchor" href="#防线总结" aria-label="Permalink to &quot;防线总结&quot;">​</a></h3><table tabindex="0"><thead><tr><th>防线</th><th>解决什么</th><th>手段</th></tr></thead><tbody><tr><td>第一道</td><td>并发覆盖</td><td>数据库乐观锁（WHERE status = &#39;UNPAID&#39;）</td></tr><tr><td>第二道</td><td>幂等性</td><td>UPDATE 返回 0 后二次查库确认状态</td></tr><tr><td>第三道</td><td>体验保障</td><td>MQ 异步退款 + 订单捞回 + Redis 分布式防抖</td></tr></tbody></table><blockquote><p><strong>面试要点</strong>：面试考的不是 API 怎么调，而是在极端场景下能不能守住系统的底线——并发安全、幂等、容错、防抖，四层思维缺一不可。</p></blockquote>`,21)])])}const g=t(l,[["render",n]]);export{c as __pageData,g as default};
